import requests
from botocore.vendored import requests

def lambda_handler(event, context):
    # Get the request and its headers
    request = event['Records'][0]['cf']['request']
    headers = request['headers']
    
    # Check if `X-Enrich-URL` is in headers
    if 'x-enrich-url' in headers:
        # Get the URL for enrichment
        enrich_url = headers['x-enrich-url'][0]['value']
        
        # Make a GET request to the URL
        response = requests.get(enrich_url)
        
        # Get the response data
        response_data = response.json()
        
        # Add the enrichment data to the request header
        request['headers']['enrichment-data'] = [{'key': 'Enrichment-Data', 'value': response_data}]

    # Return the request
    return request